do $IMPERIUM$
declare
  v_game uuid;
  v_section uuid;
begin
  select id into v_game from public.games where slug = 'ragnarok-origin-classic';
  if v_game is null then
    raise exception 'IMPERIUM: juego no encontrado: %', 'ragnarok-origin-classic';
  end if;

  -- Reemplazo idempotente: borra la sección y sus bloques, luego reinserta.
  delete from public.section_blocks where section_id in (
    select id from public.game_sections where game_id = v_game and slug = 'monturas');
  delete from public.game_sections where game_id = v_game and slug = 'monturas';

  insert into public.game_sections
    (game_id, slug, title, intro_title, intro, intro_images, is_published,
     label, description, icon, cover_image, render_type, order_index)
  values
    (v_game, 'monturas', 'Monturas', 'Cómo funcionan las monturas', 'En Ragnarok Origin Classic las monturas son ante todo un elemento de colección y estilo: cada una tiene una rareza fija, Épica o Mítica (las Míticas son las más vistosas y las más difíciles de conseguir), y por cada skin de montura que ya tengas en tu colección —aunque no la estés usando— tu personaje gana un bonus fijo de PATK +5, MATK +5, PDEF +6 y MDEF +2. Es literalmente un premio por coleccionar cuantas más, mejor.

Aparte de ese bonus por colección, cada montura tiene su propia progresión: sube de nivel (0 a 100), mejorando PATK, MATK, PS máximos y % de ATQ de arma hasta un tope en nivel 100 de +270 PATK/MATK, +3.500 PS y +15% de ATQ de arma; y acumula puntos de calidad (0 a 5.000) repartidos en cinco tipos —Brave, Clever, Lovely, Charisma y Cute— que en su tope suman hasta +851 ATQ de arma, +19% de reducción de daño y +5.804 PS máximos. Esta progresión es exactamente igual para las 48 monturas del juego (roochub.com lo confirma: "Leveling, Style and quality work the same regardless of which mount you ride"), así que lo único que de verdad distingue a una montura de otra es su rareza —por eso la tabla de abajo las agrupa así—; la web fuente tampoco publica todavía cómo se consigue cada montura en concreto.', array[]::text[], false,
     'Monturas', 'Las 48 monturas de Ragnarok Origin Classic, agrupadas por rareza (Épica o Mítica).', 'dragon', null, 'generic', 3)
  returning id into v_section;

  insert into public.section_blocks
    (section_id, order_index, title, content, source_url, is_verified, images, meta)
